import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as e,o as d,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"이미지 심사와 접근 모드","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Safety/image-moderation-and-access-mode.md","filePath":"ko-KR/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),i={name:"ko-KR/Safety/image-moderation-and-access-mode.md"};function l(n,t,h,s,c,m){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="이미지-심사와-접근-모드" tabindex="-1">이미지 심사와 접근 모드 <a class="header-anchor" href="#이미지-심사와-접근-모드" aria-label="Permalink to &quot;이미지 심사와 접근 모드&quot;">​</a></h1><p>이미지 심사와 접근 모드는 공개 범위와 연령 등급에 따라 방문자가 볼 수 있는 파일을 제어하는 기능입니다.</p><p>공개 갤러리, 랜덤 이미지 API, 외부 파일 접근과 함께 사용됩니다.</p><h2 id="할-수-있는-일" tabindex="-1">할 수 있는 일 <a class="header-anchor" href="#할-수-있는-일" aria-label="Permalink to &quot;할 수 있는 일&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>설명</th></tr></thead><tbody><tr><td>이미지 심사</td><td>파일 내용이나 등급 정보를 기록</td></tr><tr><td>블랙리스트</td><td>공개하지 않을 파일 제외</td></tr><tr><td>화이트리스트 모드</td><td>허용한 파일만 공개</td></tr><tr><td>연령 등급 제어</td><td>R12, R16, R18 등의 표시 여부 조정</td></tr><tr><td>접근 모드</td><td>방문자가 볼 수 있는 범위를 한 번에 전환</td></tr></tbody></table><h2 id="접근-모드" tabindex="-1">접근 모드 <a class="header-anchor" href="#접근-모드" aria-label="Permalink to &quot;접근 모드&quot;">​</a></h2><p>접근 모드를 사용하면 공개 페이지와 랜덤 API가 반환하는 내용을 제한할 수 있습니다.</p><p>예를 들어 전체 이용가 중심으로 운영하고 싶다면 일반 파일만 반환되도록 설정합니다. 내부용이나 제한 공개 사이트라면 운영 목적에 맞게 범위를 넓힐 수 있습니다.</p><h2 id="파일이-제한되는-경우" tabindex="-1">파일이 제한되는 경우 <a class="header-anchor" href="#파일이-제한되는-경우" aria-label="Permalink to &quot;파일이 제한되는 경우&quot;">​</a></h2><p>제한 대상 파일은 방문자에게 원래 내용 대신 접근할 수 없다는 안내가 표시됩니다.</p><p><img src="'+a+'" alt="제한된 파일" loading="lazy"></p><h2 id="운영-방식-선택" tabindex="-1">운영 방식 선택 <a class="header-anchor" href="#운영-방식-선택" aria-label="Permalink to &quot;운영 방식 선택&quot;">​</a></h2><table tabindex="0"><thead><tr><th>방식</th><th>적합한 상황</th></tr></thead><tbody><tr><td>블랙리스트 중심</td><td>기본은 공개하고 문제 파일만 제외</td></tr><tr><td>화이트리스트 중심</td><td>허용한 파일만 확실히 공개</td></tr><tr><td>연령 등급 중심</td><td>콘텐츠 등급에 따라 공개 범위 조정</td></tr></tbody></table><p>공개 사이트라면 화이트리스트나 연령 등급을 함께 쓰는 편이 의도치 않은 공개를 줄이기 좋습니다.</p><h2 id="확인할-점" tabindex="-1">확인할 점 <a class="header-anchor" href="#확인할-점" aria-label="Permalink to &quot;확인할 점&quot;">​</a></h2><ol><li>공개 갤러리에서 대상 파일이 보이는지 확인합니다.</li><li>랜덤 이미지 API가 제한 대상 파일을 반환하지 않는지 확인합니다.</li><li>블랙리스트나 화이트리스트를 바꾼 뒤 캐시 영향이 없는지 확인합니다.</li><li>자동 태그의 등급 결과를 사용할 때는 오판 가능성을 고려해 중요한 파일은 직접 확인합니다.</li></ol>',16)])])}const f=e(i,[["render",l]]);export{b as __pageData,f as default};
